async function seed() {
  console.log('Seeding RAG knowledge base with 200 Ghanaian research records...');

  // Clear existing data
  const { error: clearError } = await supabase.from('knowledge_chunks').delete().neq('id', '00000000-0000-0000-0000-000000000000');
  if (clearError) console.error('Clear error (non-fatal):', clearError.message);

  // Insert in batches
  const batchSize = 10;
  let inserted = 0;

  for (let i = 0; i < seedData.length; i += batchSize) {
    const batch = seedData.slice(i, i + batchSize);
    const { error } = await supabase.from('knowledge_chunks').insert(batch);
    if (error) {
      console.error(`Batch ${i / batchSize} error:`, error.message);
    } else {
      inserted += batch.length;
      console.log(`Inserted batch ${i / batchSize + 1}/${Math.ceil(seedData.length / batchSize)} (${batch.length} records)`);
    }
  }

  console.log(`\nDone! ${inserted} records inserted into knowledge_chunks.`);
  process.exit(0);
}

seed().catch((err) => {
  console.error('Seed failed:', err);
  process.exit(1);
});
